-- Generated by generate_base_master_seed.py
-- Base master data converted from WorkTypeSeedDataInitializer and FarmSeedDataInitializer.
-- Includes work_types and default farm structure only.
BEGIN;

-- Default work types
INSERT INTO work_types (
    code,
    name,
    template,
    is_active,
    is_system,
    is_default,
    sort_order,
    created_at,
    updated_at
) VALUES
  ('INBOUND', '입고', 'MEMO', TRUE, FALSE, TRUE, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
  ('POTTING', '포트 작업', 'REPOT', TRUE, FALSE, TRUE, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
  ('PESTICIDE', '농약', 'PESTICIDE', TRUE, FALSE, TRUE, 2, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
  ('FERTILIZER', '비료', 'FERTILIZER', TRUE, FALSE, TRUE, 3, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
  ('REPOT', '분갈이', 'REPOT', TRUE, FALSE, TRUE, 4, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
  ('STATUS', '상태 기록', 'STATUS', TRUE, FALSE, TRUE, 5, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
  ('MEMO', '일반 메모', 'MEMO', TRUE, FALSE, TRUE, 6, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
  ('LEAF_CLEANUP', '잎 정리', 'CLEANUP', TRUE, FALSE, TRUE, 7, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
  ('WEED_CLEANUP', '잡초 정리', 'CLEANUP', TRUE, FALSE, TRUE, 8, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
  ('FLOWER_CLEANUP', '단화/꽃 정리', 'CLEANUP', TRUE, FALSE, TRUE, 9, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
  ('MOVEMENT', '위치 이동', 'MOVEMENT', TRUE, TRUE, TRUE, 10, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)
ON CONFLICT (code) DO UPDATE SET
    name = EXCLUDED.name,
    template = EXCLUDED.template,
    is_active = EXCLUDED.is_active,
    is_system = EXCLUDED.is_system,
    is_default = EXCLUDED.is_default,
    sort_order = EXCLUDED.sort_order,
    updated_at = CURRENT_TIMESTAMP;

-- Farm structure: 15 houses, 3 physical beds per house, 2 default zones per bed
INSERT INTO houses (
    created_at,
    updated_at,
    memo,
    name,
    number
)
SELECT
    CURRENT_TIMESTAMP,
    CURRENT_TIMESTAMP,
    NULL,
    house_number::text || '동',
    house_number
FROM generate_series(1, 15) AS house_series(house_number)
ON CONFLICT (number) DO UPDATE SET
    name = EXCLUDED.name,
    updated_at = CURRENT_TIMESTAMP;

INSERT INTO physical_beds (
    created_at,
    updated_at,
    display_order,
    length_cm,
    memo,
    number,
    support_interval_cm,
    width_cm,
    wire_count,
    position_unit_count,
    position_unit_label,
    house_id
)
SELECT
    CURRENT_TIMESTAMP,
    CURRENT_TIMESTAMP,
    bed_number,
    NULL,
    NULL,
    bed_number,
    NULL,
    NULL,
    NULL,
    CASE WHEN bed_number = 3 THEN 28.00 ELSE 24.00 END,
    '치',
    houses.id
FROM houses
CROSS JOIN generate_series(1, 3) AS bed_series(bed_number)
WHERE houses.number BETWEEN 1 AND 15
ON CONFLICT (house_id, number) DO UPDATE SET
    display_order = EXCLUDED.display_order,
    position_unit_count = EXCLUDED.position_unit_count,
    position_unit_label = EXCLUDED.position_unit_label,
    updated_at = CURRENT_TIMESTAMP;

WITH zone_defaults(side, name, sort_order) AS (
    VALUES
        ('LEFT', '좌측', 1),
        ('RIGHT', '우측', 2)
), target_zones AS (
    SELECT
        physical_beds.id AS physical_bed_id,
        zone_defaults.side,
        zone_defaults.name,
        zone_defaults.sort_order
    FROM physical_beds
    JOIN houses ON houses.id = physical_beds.house_id
    CROSS JOIN zone_defaults
    WHERE houses.number BETWEEN 1 AND 15
      AND physical_beds.number BETWEEN 1 AND 3
)
UPDATE bed_zones
SET
    name = target_zones.name,
    sort_order = target_zones.sort_order,
    zone_type = 'DEFAULT',
    is_active = TRUE,
    updated_at = CURRENT_TIMESTAMP
FROM target_zones
WHERE bed_zones.physical_bed_id = target_zones.physical_bed_id
  AND bed_zones.side = target_zones.side;

WITH zone_defaults(side, name, sort_order) AS (
    VALUES
        ('LEFT', '좌측', 1),
        ('RIGHT', '우측', 2)
), target_zones AS (
    SELECT
        physical_beds.id AS physical_bed_id,
        zone_defaults.side,
        zone_defaults.name,
        zone_defaults.sort_order
    FROM physical_beds
    JOIN houses ON houses.id = physical_beds.house_id
    CROSS JOIN zone_defaults
    WHERE houses.number BETWEEN 1 AND 15
      AND physical_beds.number BETWEEN 1 AND 3
)
INSERT INTO bed_zones (
    created_at,
    updated_at,
    is_active,
    memo,
    name,
    side,
    sort_order,
    zone_type,
    physical_bed_id
)
SELECT
    CURRENT_TIMESTAMP,
    CURRENT_TIMESTAMP,
    TRUE,
    NULL,
    target_zones.name,
    target_zones.side,
    target_zones.sort_order,
    'DEFAULT',
    target_zones.physical_bed_id
FROM target_zones
WHERE NOT EXISTS (
    SELECT 1
    FROM bed_zones
    WHERE bed_zones.physical_bed_id = target_zones.physical_bed_id
      AND bed_zones.side = target_zones.side
);

COMMIT;
